import re
import os

def run(source):
    # Define regex patterns for each intent type
    patterns = {
        r'^create file (\w+\.\w+) with content "(.+)"$': 'create',
        r'^read file (\w+\.\w+)$': 'read',
        r'^append "(.+)" to (\w+\.\w+)$': 'append',
        r'^count lines in (\w+\.\w+)$': 'count',
        r'^copy (\w+\.\w+) to (\w+\.\w+)$': 'copy',
        r'^make directory (\w+)$': 'mkdir',
        r'^move (\w+\.\w+) to (\w+\.\w+)$': 'move',
        r'^list files$': 'ls',
        r'^list files in (\w+)$': 'ls_dir',
        r'^find files containing "(.+)"$': 'find',
        r'^delete (\w+\.\w+)$': 'delete',
        r'^delete (\w+\.\w+) confirm$': 'delete_confirm',
        r'^if (\w+\.\w+) exists then (.*) otherwise (.*)$': 'if'
    }

    # Process each line of intent
    for line in source.split('\n'):
        line = line.strip()
        if not line:
            continue

        match = None
        for pattern, cmd in patterns.items():
            match = re.match(pattern, line)
            if match:
                break

        if not match:
            continue

        if cmd == 'create':
            name, content = match.groups()
            with open(name, 'w') as f:
                f.write(content)

        elif cmd == 'read':
            name = match.group(1)
            try:
                with open(name) as f:
                    print(f.read())
            except FileNotFoundError:
                pass

        elif cmd == 'append':
            text, name = match.groups()
            with open(name, 'a') as f:
                f.write(text + '\n')

        elif cmd == 'count':
            name = match.group(1)
            try:
                with open(name) as f:
                    lines = f.readlines()
                    print(len(lines))
            except FileNotFoundError:
                pass

        elif cmd == 'copy':
            src, dst = match.groups()
            try:
                os.replace(src, dst)
            except FileNotFoundError:
                pass

        elif cmd == 'mkdir':
            name = match.group(1)
            os.makedirs(name, exist_ok=True)

        elif cmd == 'move':
            src, dst = match.groups()
            try:
                os.replace(src, dst)
            except FileNotFoundError:
                pass

        elif cmd == 'ls':
            files = os.listdir('.')
            print(' '.join(sorted(files)) if files else '(empty)')

        elif cmd == 'ls_dir':
            dir_name = match.group(1)
            files = os.listdir(dir_name)
            print(' '.join(sorted(files)) if files else '(empty)')

        elif cmd == 'find':
            text = match.group(1)
            matches = []
            for file in os.listdir('.'):
                try:
                    if text in open(file).read():
                        matches.append(file)
                except:
                    pass
            print(' '.join(sorted(matches)) if matches else '(none)')

        elif cmd == 'delete':
            name = match.group(1)
            print('REFUSED')

        elif cmd == 'delete_confirm':
            name = match.group(1)
            try:
                os.remove(name)
            except FileNotFoundError:
                pass

        elif cmd == 'if':
            cond_file, then_cmd, else_cmd = match.groups()
            if os.path.exists(cond_file):
                # Execute then_cmd
                then_lines = then_cmd.split('\n')
                for t_line in then_lines:
                    if not t_line:
                        continue
                    t_match = re.match(r'^if (\w+\.\w+) exists then (.*) otherwise (.*)$', t_line)
                    if t_match:
                        # Recursive if condition
                        run('\n'.join(then_lines))
                        break
                    else:
                        # Process as normal command
                        run(t_line)
            else:
                # Execute else_cmd
                else_lines = else_cmd.split('\n')
                for e_line in else_lines:
                    if not e_line:
                        continue
                    e_match = re.match(r'^if (\w+\.\w+) exists then (.*) otherwise (.*)$', e_line)
                    if e_match:
                        run('\n'.join(else_lines))
                        break
                    else:
                        run(e_line)
